export const ANTI_SLOP = "# Anti-Slop · 中文社媒卡片黑名单\n\n下列词、句式、标点用法在 vCard 任何 AI 输出中都不允许出现。生成完成后会做正则扫描；命中则触发一次重写，仍命中则在落库前替换/删除。\n\n## A. 营销腔禁止词\n\n破圈、出圈、入圈、内卷、躺平、赋能、抓手、闭环、链路、心智、红海、蓝海、护城河、降维打击、一文带你、深度好文、干货满满、家人们、姐妹们、宝子们\n\n## B. 网络流行语禁止词\n\n气质不符。一律避免。\n\n绝绝子、yyds、i人e人、暴击、神来之笔、封神、王炸、天花板、救命、笑死、人麻了\n\n## C. AI 标志性套句\n\nLLM 高频生成、读起来像 AI 写的、必拉黑：\n\n- \"让我们一起来探索\"\n- \"在这个数字化时代\"\n- \"无独有偶\"、\"与此同时\"、\"不仅……还……\"\n- \"不仅仅是 X，更是 Y\"\n- \"总而言之\"、\"综上所述\"\n- \"毫无疑问\"、\"众所周知\"\n- \"在不久的将来\"\n- \"随着……的发展\"\n\n## D. 句式与标点禁止\n\n- 连续 ≥ 2 个感叹号（`！！`、`!!`）\n- 反问开头（\"你知道吗？\"、\"你以为 X？其实 Y\"）\n- emoji 超量：标题超过 1 个 emoji；要点超过 1 个 emoji\n- 数字 + 百分号 + 夸张形容（\"提升 200% 不是梦\"、\"暴涨 300%\"）\n- 标题用冒号双段结构（\"X：让 Y 变得更 Z\"）\n\n## 检查规则\n\n- 字符串包含匹配（A/B 类词不区分上下文，命中即违规）\n- 套句模糊匹配：A 类整词、C 类近似（去标点 + 去空白后 includes）\n- D 类用正则：`[！!]{2,}`、`你知道[吗么]？?`、`你以为.+其实`、`(\\d+)%[^，。]{0,12}(暴|大|疯|不是梦|新高)`\n\n## 重写优先\n\n命中黑名单时，agent 应在保留原意前提下，**优先重写**为更克制的表达，而不是只删除关键词。例如：\n\n- ❌ \"Codex 让程序员破圈，YYDS！\"\n- ✅ \"Codex 把开发者的工作从写代码扩展到委派任务\"\n";

export const STRUCTURAL_RULES = "# 卡组结构规则\n\n整套卡组的版式分布与位置约束。这层约束硬性，不允许 AI 自行调整。\n\n## 位置约束\n\n- 第 1 张必须是 `cover`（封面）\n- 最后 1 张必须是 `closer`（结尾）\n- 中间各张从 `list / quote / stat` 里挑选\n\n## 分布约束\n\n- 不允许连续 3 张同类版式\n- 当卡组数 ≥ 5 张时，至少包含 2 种中间版式（不能全是 list）\n- `quote` 适合表达观点 / 引用；不适合放数据点\n- `stat` 适合表达数字 / 数据 / 比例；不适合放纯文字论点\n\n## 版式与内容的对应\n\n- **cover**：标题 + 1-2 条总览级要点（提钩 / 提问题 / 提结论）\n- **list**：标题 + 2-3 条平行要点（每条独立成立）\n- **quote**：核心观点句 + 1-2 条解释性要点（核心句可作为 blockquote 显示）\n- **stat**：1 个数字或比例 + 标题 + 1 条解释（数字本身就是论据）\n- **closer**：收束 + 行动建议或下一步暗示（不是总结，是\"留给读者一句话\"）\n\n## 必须\n\n- 整套卡组遵循同一主题，不要中途偏题\n- 如果主题包含时效性内容（最新发布、当年数据），先调用 web_search 工具 1-3 次取证再生成\n";

export const TEMPLATE_BRIEFING = "# Template · 资讯卡片（简报）\n\n**适用**：行业动态、产品发布、数据复盘。整套读起来像情报简报。\n\n## 风格\n\n- 标题：5-12 字，**必含一个判断或数字**\n- 要点：每条 ≤ 24 字；多用名词与动词，少形容词\n- 中间版式分布：`stat` ≈ 50% / `list` ≈ 40% / `quote` ≈ 10%\n- closer 用 list 收束（行动建议或数字预期）\n\n## 示例\n\n✅ 标题：\"周活同比 +18%\"\n✅ 要点：\"新用户中 62% 来自搜索，6 月新政生效后下滑\"\n✅ closer 列表：\n   - \"下一步：观察 Q3 政策变化对增长口径的影响\"\n   - \"若 7 月留存继续走低，需重新审视新用户来源\"\n\n❌ 标题：\"这次增长令人惊喜！\"\n❌ 要点：\"数据非常亮眼，非常值得关注\"\n❌ closer 用排比口号：\"一起加油 / 持续向前 / 携手共进\"\n";

export const TEMPLATE_MAGAZINE = "# Template · 编辑杂志\n\n**适用**：人物专题、行业观察、深度评论。整套读起来像杂志特稿摘要。\n\n## 风格\n\n- 标题：8-18 字，可以稍带文学性，但克制\n- 要点：每条 ≤ 36 字；可有短叙述节奏，但不煽情\n- 中间版式分布：`list` ≈ 40% / `quote` ≈ 40% / `stat` ≈ 20%\n- closer 用 quote，给一句\"留白式\"收束\n\n## 示例\n\n✅ 标题：\"这位创始人，把'失败'写进了路演稿\"\n✅ 引语：\"最危险的不是市场寒冬，是把寒冬讲成英雄叙事\"\n✅ closer：\"离开聚光灯之后，他做的第一件事是关掉评论区\"\n\n❌ 标题用排比：\"是反思，是觉醒，是跨越\"\n❌ 要点用\"破圈/天花板/封神\"等流行词\n❌ 标题加问号或感叹号制造情绪\n";

export const TEMPLATE_MINIMAL = "# Template · 极简专业\n\n**适用**：资讯拆解、技术解释、观点输出。整套读起来像编辑部专栏。\n\n## 风格\n\n- 标题：5-14 字，给一个判断或动作动词；不堆形容词\n- 要点：每条 ≤ 28 字；不用\"首先 / 其次 / 再者\"\n- 中间版式分布：`list` ≈ 50% / `stat` ≈ 30% / `quote` ≈ 20%\n- closer 用 quote 收束（一句话留给读者）\n\n## 示例\n\n✅ 标题：\"Codex 的能力边界在位移\"\n✅ 要点：\"从'给建议'转到'委派执行'，三类任务受影响\"\n✅ closer 引语：\"下一步不是更聪明的代码，是更清晰的任务拆分\"\n\n❌ 标题：\"让我们一起来探索 Codex 带来的全新可能\"\n❌ 要点：\"Codex 太牛了，简直是程序员的 YYDS\"\n❌ 标题用冒号双段：\"Codex：让程序员告别 996\"\n";

